func solve(words []string) []int64 {
    n := len(words)
    ans := make([]int64, n)
    if n == 1 {
        return []int64{0}
    }

    cp := make([]int, n-1)
    for i := 0; i < n-1; i++ {
        a, b := words[i], words[i+1]
        j := 0
        for j < len(a) && j < len(b) && a[j] == b[j] {
            j++
        }
        cp[i] = j
    }

    leftMax := make([]int, n-1)
    if n-1 > 0 {
        leftMax[0] = cp[0]
        for i := 1; i < n-1; i++ {
            if cp[i] > leftMax[i-1] {
                leftMax[i] = cp[i]
            } else {
                leftMax[i] = leftMax[i-1]
            }
        }
    }

    rightMax := make([]int, n-1)
    if n-1 > 0 {
        rightMax[n-2] = cp[n-2]
        for i := n-3; i >= 0; i-- {
            if cp[i] > rightMax[i+1] {
                rightMax[i] = cp[i]
            } else {
                rightMax[i] = rightMax[i+1]
            }
        }
    }

    for i := 0; i < n; i++ {
        if n-1 < 2 {
            ans[i] = 0
            continue
        }
        candidate := 0
        if i >= 2 {
            if candidate < leftMax[i-2] {
                candidate = leftMax[i-2]
            }
        }
        if i > 0 && i < n-1 {
            a, b := words[i-1], words[i+1]
            j := 0
            for j < len(a) && j < len(b) && a[j] == b[j] {
                j++
            }
            if candidate < j {
                candidate = j
            }
        }
        if i <= n-3 {
            if candidate < rightMax[i+1] {
                candidate = rightMax[i+1]
            }
        }
        ans[i] = int64(candidate)
    }

    return ans
}
```

### Explanation
1. **Initialization**: The solution starts by initializing the result array `ans` with zeros. If there's only one string in `words`, the result is trivially `[0]`.
2. **Precompute Adjacent Prefixes**: The array `cp` stores the common prefix lengths for each adjacent pair in the original `words` array.
3. **Prefix Maximum Arrays**: The arrays `leftMax` and `rightMax` store the maximum common prefix values up to each index from the start and from each index to the end, respectively.
4. **Processing Each Removal**:
   - For each index `i`, if the modified array has less than two elements, the result is `0`.
   - Otherwise, the result is derived from:
     - The maximum common prefix in the left segment (up to `i-2`).
     - The common prefix of the new adjacent pair formed by `words[i-1]` and `words[i+1]` (if applicable).
     - The maximum common prefix in the right segment (starting from `i+1`).
5. **Efficiency**: By leveraging precomputed values and efficient segment checks, the solution processes each removal in constant time (amortized), making it suitable for large inputs.
